function buildCasino(slug: string, name: string, rating: number, summary: string, pros: string[], cons: string[]): CasinoData {
  const reviewSections = OVERVIEW_BY_SLUG[slug]
    ? OVERVIEW_BY_SLUG[slug].map((s) => ({ heading: replaceName(s.heading, name), content: replaceName(s.content, name) }))
    : SHARED.reviewSections.map((s) => ({ heading: replaceName(s.heading, name), content: replaceName(s.content, name) }));
  const bonuses = BONUSES_BY_SLUG[slug] ?? SHARED.bonuses;
  return {
    slug,
    name,
    logo: getBonusLogoUrl(slug),
    banner: SHARED.banner,
    rating,
    playNowUrl: AFFILIATE_URL_BY_SLUG[slug] ?? `https://${slug}.com`,
    summary,
    pros,
    cons,
    trustBadges: SHARED.trustBadges,
    license: SHARED.license,
    withdrawalLimit: WITHDRAWAL_LIMIT_BY_SLUG[slug] ?? 'See site for details',
    trustScoreBy: SHARED.trustScoreBy,
    trustLabel: SHARED.trustLabel,
    keyFacts: SHARED.keyFacts,
    bonuses,
    games: SHARED.games,
    banking: SHARED.banking,
    review: SHARED.review.map((r) => ({ ...r, content: r.content.replace(/Sugar96 Casino|Sugar96|this casino/gi, name) })),
    reviewSections,
  };
}

