export const casinoDatabase: Record<string, CasinoData> = Object.fromEntries(
  LIST.map((c) => [c.slug, buildCasino(c.slug, c.name, c.rating, c.summary, c.pros, c.cons)])
);

export const getCasinoBySlug = (slug: string): CasinoData | undefined => {
  return casinoDatabase[slug];
};

export const getAllCasinoSlugs = (): string[] => {
  return Object.keys(casinoDatabase);
};
